/**
 * One-off: rewrite the 9 Workwell service-page docs with ORIGINAL, differentiated
 * copy generated by Gemini grounded on live Google Search (current UK tax facts).
 * Keeps testimonial + price; replaces headline/description/features/benefits/faqs/
 * stats/meta. No fabricated client stats — stats are true-claim pairs only.
 *
 *   node scripts/rewrite-workwell-service-copy.mjs           # all 9
 *   node scripts/rewrite-workwell-service-copy.mjs sole-trader  # one (test)
 */
import { createClient } from "@sanity/client";
import { readFileSync, existsSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const env = join(ROOT, ".env.local");
if (existsSync(env))
  for (const l of readFileSync(env, "utf8").split(/\r?\n/)) {
    const m = l.match(/^\s*([A-Z0-9_]+)\s*=\s*(.*)$/);
    if (m && !process.env[m[1]]) process.env[m[1]] = m[2].replace(/^["']|["']$/g, "");
  }
const GEMINI_KEY = process.env.GEMINI_API_KEY;
if (!GEMINI_KEY) { console.error("✗ GEMINI_API_KEY not set"); process.exit(1); }
const sanity = createClient({ projectId: "sgaod5tg", dataset: "production", apiVersion: "2024-01-01", token: process.env.SANITY_TOKEN, useCdn: false });

const VOICE =
  "Workwell Accountancy is a UK online accountancy firm with dedicated, named accountants, free FreeAgent software, and one fixed monthly fee. Voice: professional, modern, proactive, genuinely helpful; plain British English; warm but not gimmicky; no hype, no jargon, no exclamation marks.";

const PAGES = {
  "sole-trader": { title: "Sole Trader Accountants", audience: "newly self-employed sole traders and the self-employed", focus: "Self Assessment, allowable expenses (actual vs simplified), Class 4 National Insurance, payments on account, the VAT registration threshold, Making Tax Digital for Income Tax and when a sole trader should consider a limited company" },
  "limited-company": { title: "Limited Company Accountants", audience: "directors of small UK limited companies", focus: "Corporation Tax (small profits rate vs main rate and marginal relief), the most tax-efficient salary/dividend split, director payroll and RTI, Companies House accounts and the confirmation statement, dividend allowance and dividend tax rates" },
  "contractor-accountancy": { title: "Contractor Accountants", audience: "UK contractors working through a limited company (PSC) or umbrella", focus: "IR35 / off-payroll working rules, inside vs outside IR35, switching between PSC and umbrella, dividend planning, expenses a contractor can claim" },
  "freelancer-accountancy": { title: "Freelancer Accountants", audience: "freelancers and creative self-employed people with irregular income", focus: "Self Assessment, managing irregular income and tax set-aside, allowable expenses for freelancers, when to register for VAT, sole trader vs limited company" },
  "landlord-accounting": { title: "Landlord Accountants", audience: "UK residential and portfolio landlords", focus: "property rental income and Self Assessment, the Section 24 mortgage-interest finance-cost restriction, allowable property expenses, Capital Gains Tax on selling a rental, Making Tax Digital for landlords, incorporation of a property portfolio" },
  "accounting-for-startups": { title: "Accountants for Startups", audience: "founders of early-stage UK startups", focus: "choosing and forming the right structure, registering with HMRC and Companies House, R&D tax relief, SEIS/EIS for raising investment, getting bookkeeping and payroll set up correctly from day one" },
  "ecommerce-accounting": { title: "Ecommerce Accountants", audience: "online sellers on Amazon, eBay, Etsy and Shopify", focus: "marketplace sales and fee reconciliation, VAT including the OSS and IOSS schemes for cross-border sales, accounting for inventory and cost of goods sold, the VAT registration threshold, sole trader vs limited company for an online store" },
  "small-business-accountant": { title: "Small Business Accountants", audience: "owners of small UK limited companies", focus: "year-end statutory accounts and the Corporation Tax return, VAT, director and staff payroll, Companies House filing deadlines, tax-efficient profit extraction, what a complete small-company accounting package should include" },
  "cis-accounting": { title: "CIS Accountants", audience: "contractors and subcontractors in the Construction Industry Scheme", focus: "how CIS works, the 20% vs 30% deduction rates and gross payment status, monthly CIS returns and subcontractor verification, reclaiming overpaid CIS deductions, sole trader vs limited company for construction" },
};

async function generate(slug, p) {
  const prompt = `You are writing the website copy for the "${p.title}" page on Workwell Accountancy's site.
${VOICE}

Audience for THIS page: ${p.audience}.
Topics this page should genuinely help with: ${p.focus}.

Write ORIGINAL, DIFFERENTIATED copy — do NOT use generic "dedicated accountant, unlimited advice, fixed fee" boilerplate as the lead; instead lead with the SPECIFIC real concerns of ${p.audience} and how Workwell solves them. It must read as Workwell's own page, not a generic accountant template.

Accuracy rules (important): use CURRENT UK tax facts for the 2025/26 and 2026/27 tax years. Ground every figure (thresholds, rates, deadlines, scheme rules) using up-to-date web sources. If you are not confident of a current figure, describe it qualitatively rather than stating a wrong number. Do NOT invent statistics, client numbers, ratings, awards, or testimonials.

Return ONLY a single JSON object — no markdown, no code fences, no commentary — with exactly these keys:
{
  "headline": "hero headline, confident, max 9 words",
  "description": "hero paragraph, 2 sentences, specific to this audience",
  "features": ["8-10 short 'what's included / what we handle' lines specific to this audience"],
  "benefits": [{"title":"3-5 words","description":"1-2 sentences"} , ...exactly 4],
  "faqs": [{"question":"a real question this audience asks","answer":"2-4 sentences, accurate and helpful"} , ...exactly 5],
  "stats": [{"value":"e.g. £0","label":"e.g. Setup fees"} , ...exactly 4 — TRUE claims only (fees, what's included, support), never invented metrics or client counts],
  "metaTitle": "max 60 chars, includes the service",
  "metaDescription": "120-160 chars, specific to this audience"
}`;

  const res = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-latest:generateContent?key=${GEMINI_KEY}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }],
        tools: [{ google_search: {} }],
        generationConfig: { temperature: 0.7 },
      }),
    }
  );
  const data = await res.json();
  if (!res.ok) throw new Error(`Gemini ${res.status}: ${JSON.stringify(data).slice(0, 300)}`);
  let text = (data?.candidates?.[0]?.content?.parts || []).map((x) => x.text).filter(Boolean).join("");
  if (!text) throw new Error("empty response: " + JSON.stringify(data).slice(0, 300));
  text = text.replace(/```json/gi, "").replace(/```/g, "").trim();
  const s = text.indexOf("{"), e = text.lastIndexOf("}");
  return JSON.parse(text.slice(s, e + 1));
}

const key = (pfx, i) => `${pfx}-${i}`;

async function run() {
  const only = process.argv[2];
  const slugs = only ? [only] : Object.keys(PAGES);
  for (const slug of slugs) {
    const p = PAGES[slug];
    if (!p) { console.log("skip unknown", slug); continue; }
    try {
      const c = await generate(slug, p);
      const patch = {
        headline: c.headline,
        description: c.description,
        features: (c.features || []).slice(0, 12),
        benefits: (c.benefits || []).slice(0, 4).map((b, i) => ({ _key: key("ben", i), title: b.title, description: b.description })),
        faqs: (c.faqs || []).slice(0, 6).map((f, i) => ({ _key: key("faq", i), question: f.question, answer: f.answer })),
        stats: (c.stats || []).slice(0, 4).map((st, i) => ({ _key: key("stat", i), value: st.value, label: st.label })),
        metaTitle: c.metaTitle,
        metaDescription: c.metaDescription,
      };
      await sanity.patch(`servicePage-${slug}`).set(patch).commit();
      console.log(`✓ ${slug}: "${c.headline}" — ${patch.features.length} feats, ${patch.faqs.length} faqs`);
    } catch (err) {
      console.log(`✗ ${slug}: ${err.message}`);
    }
  }
}
run();
